const canvas = document.getElementById('c');
const ctx = canvas.getContext('2d');
const W = 800, H = 500;

function resize() {
  const maxW = window.innerWidth - 40;
  const maxH = window.innerHeight - 120; 
  const ratio = Math.min(maxW / W, maxH / H);

  const dpr = window.devicePixelRatio || 1;

  canvas.style.width  = Math.floor(W * ratio) + 'px';
  canvas.style.height = Math.floor(H * ratio) + 'px';

  canvas.width  = Math.floor(W * ratio * dpr);
  canvas.height = Math.floor(H * ratio * dpr);
}
resize();
window.addEventListener('resize', resize);

function sc() { 
  return canvas.width / W; 
}

// ── Audio Setup ──────────────────────────────────────────
let globalVolume = 0.3; 
const sfxMultiplier = 2.5; 

const audioMenu = new Audio('menu_music.mp3');
audioMenu.loop = true;

const audioLevel1 = new Audio('level1_music.mp3');
audioLevel1.loop = true;

const audioLevel2 = new Audio('level2_music.mp3');
audioLevel2.loop = true;

const audioLevel3 = new Audio('level3_music.mp3');
audioLevel3.loop = true;

const audioFold = new Audio('fold_sound.mp3');
const audioJump = new Audio('jump_sound.mp3');
const audioPickup = new Audio('pickup_sound.wav');
const audioExit = new Audio('exit_sound.mp3');
const audioDeath = new Audio('death_sound.mp3');

const levelTracks = [audioLevel1, audioLevel2, audioLevel3];
let currentTrack = null;

function applyVolumeToAll() {
  [audioMenu, ...levelTracks].forEach(track => {
    if (track) track.volume = globalVolume;
  });
  
  [audioFold, audioJump, audioPickup, audioExit, audioDeath].forEach(sfx => {
    if (sfx) sfx.volume = Math.min(1.0, globalVolume * sfxMultiplier);
  });
}
applyVolumeToAll();

function playTrack(track) {
  if (currentTrack === track) return; 
  
  if (currentTrack) {
    currentTrack.pause();
    currentTrack.currentTime = 0; 
  }
  
  currentTrack = track;
  
  if (currentTrack) {
    currentTrack.volume = globalVolume;
    currentTrack.play().catch((err) => {
        console.error("Audio failed to play:", err);
    });
  }
}

function playSound(audioObj) {
  if (!audioObj) return;
  audioObj.volume = Math.min(1.0, globalVolume * sfxMultiplier);
  if (audioObj.readyState > 0) {
    audioObj.currentTime = 0; 
  }
  audioObj.play().catch(() => {});
}

playTrack(audioMenu);

const startAudioContext = () => {
  if (currentTrack && currentTrack.paused) {
    currentTrack.play().catch(()=>{});
  }
  document.removeEventListener('keydown', startAudioContext);
  document.removeEventListener('mousedown', startAudioContext);
};
document.addEventListener('keydown', startAudioContext);
document.addEventListener('mousedown', startAudioContext);

// ── Image & Sprite Setup ─────────────────────────────────
const FRAME_W = 128, FRAME_H = 128, FRAME_COUNT = 8;
let spriteReady = false;
let spriteCanvas = null;

const rawImg = new Image();
rawImg.onload = function() {
  const oc = document.createElement('canvas');
  oc.width  = rawImg.width;
  oc.height = rawImg.height;
  const oc2 = oc.getContext('2d');
  oc2.drawImage(rawImg, 0, 0);
  const imageData = oc2.getImageData(0, 0, oc.width, oc.height);
  const d = imageData.data;
  for (let i = 0; i < d.length; i += 4) {
    const r = d[i], g = d[i+1], b = d[i+2];
    const brightness = 0.299*r + 0.587*g + 0.114*b;
    if (brightness < 30) d[i+3] = 0;
    else if (brightness < 60) d[i+3] = Math.round(((brightness - 30) / 30) * 255);
  }
  oc2.putImageData(imageData, 0, 0);
  spriteCanvas = oc;
  spriteReady = true;
};

let exitImgReady = false;
const exitImg = new Image();
exitImg.onload = function() { exitImgReady = true; };
exitImg.onerror = function() { console.error("Error: Exit image Base64 failed to load."); };

let pickupImgReady = false;
const pickupImg = new Image();
pickupImg.onload = function() { pickupImgReady = true; };
pickupImg.onerror = function() { console.error("Error: Pickup image Base64 failed to load."); };

