// ── Input ────────────────────────────────────────────────
const keys = {};
document.addEventListener('keydown', e => {
  keys[e.code] = true;
  if (['Space','ArrowUp','ArrowDown','ArrowLeft','ArrowRight','KeyF','KeyR','KeyA','KeyD','KeyS'].includes(e.code)) e.preventDefault();
});
document.addEventListener('keyup', e => { keys[e.code] = false; });

let mouseX = W / 2;
canvas.addEventListener('mousemove', e => {
  const r = canvas.getBoundingClientRect();
  const cssScale = canvas.clientWidth / W;
  mouseX = (e.clientX - r.left) / cssScale;
});

// ── Constants ─────────────────────────────────────────────
const GRAVITY = 0.45, JUMP_V = -11, SPEED = 2.0;

// ── State ─────────────────────────────────────────────────
let state = 'menu';
let levelIdx = 0;
let folded = false, foldMode = false, foldAxis = W / 2;
let foldCount = 0, timer = 0, timerOn = false;
let player;
let frameIdx = 0, frameTimer = 0;
const FRAME_SPEED = 8; 
let facingLeft = false;
let lastNonPauseState = 'menu';

// ── Levels ────────────────────────────────────────────────
