function resetLevel(i) {
  const lv = LEVELS[i];
  player = {x:lv.ps.x,y:lv.ps.y,w:22,h:36,vx:0,vy:0,onGround:false};
  folded=false; foldMode=false; foldAxis=W/2;
  foldCount=0; timer=0; timerOn=true; 
  frameIdx=0; frameTimer=0; facingLeft=false;
  lv.cranes.forEach(c=>c.ok=false);
}

function effectivePlatforms() {
  const lv = LEVELS[levelIdx];
  if (!folded) return lv.platforms;
  const eff = [];
  for (const p of lv.platforms) {
    if (p.fp) {
      if (p.x < foldAxis) eff.push({...p, w: Math.min(p.x+p.w,foldAxis)-p.x});
      continue;
    }
    if (p.x < foldAxis) {
      const w = Math.min(p.x+p.w,foldAxis)-p.x;
      if (w>0) eff.push({...p,w});
    }
    if (p.x+p.w > foldAxis) {
      const lx=Math.max(p.x,foldAxis),rx=p.x+p.w,sw=rx-lx,mx=2*foldAxis-rx;
      if (mx+sw>0) eff.push({...p,x:mx,w:sw,mirrored:true});
    }
  }
  return eff;
}

function effectiveHazards() {
  const lv = LEVELS[levelIdx];
  if (!folded) return lv.hazards;
  const eff = [];
  for (const h of lv.hazards) {
    if (h.x < foldAxis) {
      const w = Math.min(h.x + h.w, foldAxis) - h.x;
      if (w > 0) eff.push({...h, w});
    }
    if (h.x + h.w > foldAxis) {
      const lx = Math.max(h.x, foldAxis);
      const rx = h.x + h.w;
      const sw = rx - lx;
      const mx = 2 * foldAxis - rx;
      if (mx + sw > 0) eff.push({...h, x: mx, w: sw, mirrored: true});
    }
  }
  return eff;
}

function mirrorX(x,w) { return (folded && x>foldAxis) ? 2*foldAxis-x-w : x; }
function overlap(ax,ay,aw,ah,bx,by,bw,bh) { return ax<bx+bw&&ax+aw>bx&&ay<by+bh&&ay+ah>by; }

function resolveCollisions(plats) {
  player.onGround = false;
  for (const p of plats) {
    if (!overlap(player.x,player.y,player.w,player.h,p.x,p.y,p.w,p.h)) continue;
    const ol=(player.x+player.w)-p.x, or_=(p.x+p.w)-player.x;
    const ot=(player.y+player.h)-p.y, ob=(p.y+p.h)-player.y;
    const mn=Math.min(ol,or_,ot,ob);
    if      (mn===ot&&player.vy>=0) { player.y=p.y-player.h; player.vy=0; player.onGround=true; }
    else if (mn===ob&&player.vy<=0) { player.y=p.y+p.h; player.vy=0; }
    else if (mn===ol)               { player.x=p.x-player.w; player.vx=0; }
    else                            { player.x=p.x+p.w; player.vx=0; }
  }
}

// ── Update ────────────────────────────────────────────────
function update() {
  if (state!=='playing') return;
  const lv = LEVELS[levelIdx];
  if (timerOn) timer += 1/60;

  const axPrev = Math.max(60, Math.min(W-60, mouseX));
  if (keys['KeyF']&&!folded) { foldMode=true; foldAxis=axPrev; }
  
  if (foldMode&&!keys['KeyF']) {
    foldMode=false; folded=true; foldCount++;
    if (player.x+player.w>foldAxis) player.x=foldAxis-player.w-2;
    playSound(audioFold);
  }
  
  if (keys['KeyR'] && folded) {
    folded=false;
    playSound(audioFold);
  }

  player.vx=0;
  if (keys['KeyA']||keys['ArrowLeft'])  { player.vx=-SPEED; facingLeft=true;  }
  if (keys['KeyD']||keys['ArrowRight']) { player.vx= SPEED; facingLeft=false; }
  if ((keys['Space']||keys['ArrowUp'])&&player.onGround) { 
    player.vy=JUMP_V; 
    player.onGround=false; 
    playSound(audioJump); 
  }

  player.vy=Math.min(player.vy+GRAVITY,16);
  player.x+=player.vx; player.y+=player.vy;
  if (folded&&player.x+player.w>foldAxis) player.x=foldAxis-player.w-1;
  player.x=Math.max(0,Math.min(player.x,W-player.w));
  resolveCollisions(effectivePlatforms());

  const isMoving = Math.abs(player.vx) > 0.01;
  
  if (!player.onGround) {
    frameIdx = 1; 
    frameTimer = 0;
  } else if (isMoving) {
    frameTimer++;
    if (frameTimer >= FRAME_SPEED) { 
      frameTimer = 0; 
      frameIdx++;
      if (frameIdx >= FRAME_COUNT) frameIdx = 0; 
    }
  } else {
    frameIdx = 0; 
    frameTimer = 0;
  }

  // Death
  if (player.y>H+80) { 
    playSound(audioDeath);
    state='dead'; 
    return; 
  }
  for (const h of effectiveHazards()) {
    if (overlap(player.x, player.y, player.w, player.h, h.x, h.y, h.w, h.h)) { 
      playSound(audioDeath);
      state='dead'; 
      return; 
    }
  }
  
  // Collectible Pickup logic
  for (const c of lv.cranes) {
    if (c.ok) continue;
    const cx=(folded&&c.x>foldAxis)?2*foldAxis-c.x:c.x;
    if (folded&&cx>foldAxis) continue;
    if (overlap(player.x,player.y,player.w,player.h,cx-12,c.y-12,24,24)) {
      c.ok=true;
      playSound(audioPickup);
    }
  }

  // Level Completion logic
  const ex=lv.exit;
  const exX=(folded&&ex.x>foldAxis)?2*foldAxis-ex.x:ex.x;
  if (!folded||exX<foldAxis) {
    if (overlap(player.x,player.y,player.w,player.h,exX-16,ex.y-16,32,32)) {
      playSound(audioExit);
      state = 'levelComplete';
      timerOn = false;
    }
  }
}

// ── Draw helpers ──────────────────────────────────────────
function drawCrane(cx,cy,sz,col) {
  const s=sc();
  ctx.save(); ctx.translate(cx*s,cy*s); ctx.fillStyle=col;
  ctx.beginPath(); ctx.moveTo(0,-sz*s); ctx.lineTo(sz*.6*s,sz*.2*s); ctx.lineTo(0,sz*.5*s); ctx.lineTo(-sz*.6*s,sz*.2*s); ctx.closePath(); ctx.fill();
  ctx.beginPath(); ctx.moveTo(-sz*.6*s,sz*.2*s); ctx.lineTo(-sz*1.1*s,-sz*.3*s); ctx.lineTo(0,sz*.5*s); ctx.fill();
  ctx.beginPath(); ctx.moveTo(sz*.6*s,sz*.2*s);  ctx.lineTo(sz*1.1*s,-sz*.3*s);  ctx.lineTo(0,sz*.5*s); ctx.fill();
  ctx.restore();
}

function drawPlatform(p) {
  const s=sc(), x=p.x*s, y=p.y*s, w=p.w*s, h=p.h*s;
  // NEW COLOR PALETTE: Dark Slate for normal, Cyan for folded, Purple for fold-proof
  ctx.fillStyle = p.mirrored ? '#0277bd' : (p.fp ? '#4527a0' : '#263238');
  ctx.fillRect(x,y,w,h);
  
  ctx.fillStyle = p.mirrored ? '#4fc3f7' : (p.fp ? '#7e57c2' : '#546e7a');
  ctx.fillRect(x,y,w,3*s);
  
  if (!p.fp) {
    ctx.strokeStyle='rgba(0,0,0,0.15)'; ctx.lineWidth=1;
    for (let xi=x+20*s;xi<x+w;xi+=20*s) { ctx.beginPath(); ctx.moveTo(xi,y); ctx.lineTo(xi,y+h); ctx.stroke(); }
  } else {
    ctx.strokeStyle='#b388ff'; ctx.lineWidth=1.5*s; ctx.strokeRect(x,y,w,h);
  }
}

function drawSpike(hx, hy, hw, hh) {
  const s = sc();
  ctx.save();
  
  ctx.beginPath();
  ctx.rect(hx * s, (hy - 15) * s, hw * s, (hh + 15) * s);
  ctx.clip();

  ctx.fillStyle = '#aa2200'; 
  ctx.fillRect(hx * s, hy * s, hw * s, hh * s);
  
  ctx.fillStyle = '#ff3311';
  for (let xi = hx * s; xi < (hx + hw) * s; xi += 10 * s) {
    ctx.beginPath(); 
    ctx.moveTo(xi, hy * s); 
    ctx.lineTo(xi + 5 * s, (hy - 10) * s); 
    ctx.lineTo(xi + 10 * s, hy * s); 
    ctx.fill();
  }
  
  ctx.restore();
}

function drawPlayer() {
  const s=sc();
  const px=player.x*s, py=player.y*s, pw=player.w*s, ph=player.h*s;

  if (spriteReady && spriteCanvas) {
    ctx.save();
    const sx = frameIdx * FRAME_W;
    const destW = pw * 2.2;
    const destH = ph * 1.35;
    const destX = px + pw/2 - destW/2;
    const destY = py + ph - destH;

    if (facingLeft) {
      ctx.translate(destX + destW, destY);
      ctx.scale(-1, 1);
      ctx.drawImage(spriteCanvas, sx, 0, FRAME_W, FRAME_H, 0, 0, destW, destH);
    } else {
      ctx.drawImage(spriteCanvas, sx, 0, FRAME_W, FRAME_H, destX, destY, destW, destH);
    }
    ctx.restore();
  } else {
    ctx.fillStyle='#1a0e04'; ctx.fillRect(px,py,pw,ph);
    ctx.fillStyle='#ffcc44';
    ctx.beginPath(); ctx.arc(px+pw/2,py+5*s,6*s,0,Math.PI*2); ctx.fill();
  }
}

function drawBG() {
  // NEW BACKGROUND: Crisp cool off-white
  ctx.fillStyle='#f0f4f8'; 
  ctx.fillRect(0,0,canvas.width,canvas.height);
  
  // NEW GRID: Light blue-grey
  ctx.strokeStyle='rgba(144,164,174,0.25)'; 
  ctx.lineWidth=0.5;
  const s=sc();
  for (let x=0;x<W;x+=20) { ctx.beginPath(); ctx.moveTo(x*s,0); ctx.lineTo(x*s,H*s); ctx.stroke(); }
  for (let y=0;y<H;y+=20) { ctx.beginPath(); ctx.moveTo(0,y*s); ctx.lineTo(W*s,y*s); ctx.stroke(); }
}

function drawHUD() {
  const s=sc(), lv=LEVELS[levelIdx];
  ctx.save(); ctx.scale(s,s);
  
  // NEW HUD: Dark Slate
  ctx.fillStyle='rgba(38,50,56,0.9)'; 
  ctx.fillRect(0,0,W,34);
  
  // HUD Text: Bright Off-White
  ctx.fillStyle='#eceff1'; 
  ctx.font='bold 13px MyCustomFont';
  ctx.fillText(`Folds: ${foldCount}`,14,22);
  const mm=String(Math.floor(timer/60)).padStart(2,'0'), ss2=String(Math.floor(timer%60)).padStart(2,'0');
  ctx.textAlign='right'; ctx.fillText(`${mm}:${ss2}`,W-14,22); ctx.textAlign='left';
  const got=lv.cranes.filter(c=>c.ok).length;
  
  ctx.fillStyle='#d4a020'; ctx.textAlign='center';
  ctx.fillText(`✦ ${got}/${lv.cranes.length}   ${lv.name}`,W/2,22);
  ctx.textAlign='left';
  
  if (folded) {
    ctx.fillStyle='rgba(38,50,56,0.8)'; ctx.fillRect(W-118,38,114,24);
    ctx.fillStyle='#4fc3f7'; ctx.font='11px MyCustomFont'; ctx.fillText('Press R to Unfold',W-108,54);
  }
  ctx.restore();
}

function rrect(x,y,w,h,r,fill,stroke) {
  ctx.beginPath(); ctx.moveTo(x+r,y);
  ctx.lineTo(x+w-r,y); ctx.quadraticCurveTo(x+w,y,x+w,y+r);
  ctx.lineTo(x+w,y+h-r); ctx.quadraticCurveTo(x+w,y+h,x+w-r,y+h);
  ctx.lineTo(x+r,y+h); ctx.quadraticCurveTo(x,y+h,x,y+h-r);
  ctx.lineTo(x,y+r); ctx.quadraticCurveTo(x,y,x+r,y);
  ctx.closePath();
  if (fill) { ctx.fillStyle=fill; ctx.fill(); }
  if (stroke) { ctx.strokeStyle=stroke; ctx.lineWidth=1.5; ctx.stroke(); }
}

