function drawLevelComplete() {
  drawGame();
  const s = sc();
  ctx.save(); ctx.scale(s, s);
  ctx.fillStyle = 'rgba(15,23,42,0.58)';
  ctx.fillRect(0, 0, W, H);
  
  rrect(210, 100, 380, 290, 8, 'rgba(38,50,56,0.95)', '#00e676');
  
  const isLastLevel = levelIdx === LEVELS.length - 1;
  const lv = LEVELS[levelIdx];
  const got = lv.cranes.filter(c => c.ok).length;
  const total = lv.cranes.length;
  
  ctx.fillStyle = '#00e676'; ctx.font = 'bold 36px MyCustomFont'; ctx.textAlign = 'center';
  ctx.fillText(isLastLevel ? 'Game Complete!' : 'Level Complete!', W/2, 150);
  
  ctx.fillStyle = '#eceff1'; ctx.font = '18px MyCustomFont';
  const mm = String(Math.floor(timer/60)).padStart(2,'0');
  const ss2 = String(Math.floor(timer%60)).padStart(2,'0');
  ctx.fillText(`Time: ${mm}:${ss2}`, W/2, 195);
  ctx.fillText(`Folds Used: ${foldCount}`, W/2, 225);
  ctx.fillText(`Cranes Collected: ${got} / ${total}`, W/2, 255);
  
  ctx.fillStyle = '#4fc3f7'; ctx.font = '14px MyCustomFont';
  if (!isLastLevel) {
    ctx.fillText('Press ENTER for Next Level', W/2, 310);
  } else {
    ctx.fillText('Press ENTER to return to Menu', W/2, 310);
  }
  ctx.fillText('Press R to Restart Level', W/2, 335);
  ctx.fillText('Press M for Menu', W/2, 360);
  
  ctx.textAlign = 'left';
  ctx.restore();
}

function drawGame() {
  drawBG();
  const lv=LEVELS[levelIdx];
  const s=sc();
  const axPrev=Math.max(60,Math.min(W-60,mouseX));

  if (foldMode) {
    ctx.save(); ctx.scale(s,s);
    
    // NEW FOLD PREVIEW TINT
    ctx.fillStyle='rgba(3,169,244,0.1)'; 
    ctx.fillRect(axPrev,0,W-axPrev,H);
    ctx.globalAlpha=0.28;
    
    for (const p of lv.platforms) {
      if (p.fp) continue;
      if (p.x+p.w>axPrev) {
        const lx=Math.max(p.x,axPrev),rx=p.x+p.w,sw=rx-lx,mx=2*axPrev-rx;
        ctx.fillStyle='#4fc3f7'; ctx.fillRect(mx,p.y,sw,p.h);
      }
    }
    ctx.globalAlpha=1;
    
    // NEW FOLD LINE: CYAN
    ctx.strokeStyle='#0288d1'; ctx.lineWidth=2/s;
    ctx.setLineDash([8/s,4/s]);
    ctx.beginPath(); ctx.moveTo(axPrev,0); ctx.lineTo(axPrev,H); ctx.stroke();
    ctx.setLineDash([]);
    
    // TEXT COLOR CHANGED to darker cyan
    ctx.fillStyle='#01579b'; ctx.font=`bold ${36/s}px MyCustomFont`; ctx.textAlign='center';
    ctx.fillText('Release F to fold here',axPrev,180/s);
    ctx.textAlign='left'; ctx.restore();
  }

  if (folded) {
    ctx.save(); ctx.scale(s,s);
    
    // FOLDED AREA OVERLAY
    ctx.fillStyle='rgba(144,164,174,0.2)'; 
    ctx.fillRect(foldAxis,0,W-foldAxis,H);
    
    // SOLID FOLD CREASE LINE
    ctx.strokeStyle='#0277bd'; ctx.lineWidth=3/s;
    ctx.beginPath(); ctx.moveTo(foldAxis,0); ctx.lineTo(foldAxis,H); ctx.stroke();
    ctx.restore();
  }

  for (const p of effectivePlatforms()) drawPlatform(p);
  
  for (const h of effectiveHazards()) {
    drawSpike(h.x, h.y, h.w, h.h);
  }
  
  for (const c of lv.cranes) {
    if (c.ok) continue;
    const cx=(folded&&c.x>foldAxis)?2*foldAxis-c.x:c.x;
    if (folded&&cx>foldAxis) continue;
    
    if (pickupImgReady) {
      ctx.drawImage(pickupImg, (cx - 12) * s, (c.y - 12) * s, 24 * s, 24 * s);
    } else {
      drawCrane(cx,c.y,9,'#d4a020');
    }
  }
  
  const ex=lv.exit;
  const exX=(folded&&ex.x>foldAxis)?2*foldAxis-ex.x:ex.x;
  if (!folded||exX<foldAxis) {
    if (exitImgReady) {
      ctx.drawImage(exitImg, (exX - 16) * s, (ex.y - 16) * s, 32 * s, 32 * s);
    } else {
      drawCrane(exX,ex.y,14,'#00dd66');
      ctx.save();
      ctx.strokeStyle='rgba(0,220,100,0.3)'; ctx.lineWidth=6*s;
      ctx.beginPath(); ctx.arc(exX*s,ex.y*s,18*s,0,Math.PI*2); ctx.stroke();
      ctx.restore();
    }
  }

  drawPlayer();
  drawHUD();

  if (timer<7) {
    ctx.save(); ctx.scale(s,s);
    ctx.fillStyle='rgba(38,50,56,0.85)'; ctx.fillRect(0,H-50,W,50);
    ctx.fillStyle='#eceff1'; ctx.font='22px MyCustomFont'; ctx.textAlign='center';
    ctx.fillText(lv.hint,W/2,H-18);
    ctx.textAlign='left'; ctx.restore();
  }
}

document.addEventListener('keydown', e => {
  if (e.code==='Escape') {
    if (state==='playing') {
      lastNonPauseState = 'playing';
      state='paused';
    } else if (state==='paused') {
      state=lastNonPauseState;
    }
  }

  if (state === 'paused') {
    if (e.code === 'ArrowUp' || e.key === '+' || e.key === '=') {
      globalVolume = Math.min(1.0, globalVolume + 0.1);
      applyVolumeToAll();
    }
    if (e.code === 'ArrowDown' || e.key === '-' || e.key === '_') {
      globalVolume = Math.max(0.0, globalVolume - 0.1);
      applyVolumeToAll();
    }
  }

  if (e.code==='Enter') {
    if (state==='menu') { 
      state='playing'; levelIdx=0; resetLevel(0); 
      playTrack(levelTracks[levelIdx]);
    }
    else if (state==='paused' || state==='dead') { 
      resetLevel(levelIdx); state='playing'; 
    } 
    else if (state==='levelComplete') {
      if (levelIdx < LEVELS.length - 1) {
        levelIdx++;
        resetLevel(levelIdx);
        state = 'playing';
        playTrack(levelTracks[levelIdx]);
      } else {
        state = 'menu';
        playTrack(audioMenu);
      }
    }
  }

  if (e.code==='KeyM') {
    if (state==='paused' || state==='levelComplete') {
      state='menu';
      playTrack(audioMenu);
    }
  }

  if (e.code==='KeyR') {
    if (state==='levelComplete') {
      resetLevel(levelIdx); 
      state='playing';
    }
  }
});

let lastTime = 0;
const FPS = 60;
const frameInterval = 1000 / FPS;

function loop(timestamp) {
  requestAnimationFrame(loop);
  
  if (!timestamp) timestamp = 0;
  const deltaTime = timestamp - lastTime;
  
  if (deltaTime >= frameInterval) {
    lastTime = timestamp - (deltaTime % frameInterval);
    
    update();
    if      (state==='menu')          drawMenu();
    else if (state==='paused')        drawPause();
    else if (state==='dead')          drawDead();
    else if (state==='levelComplete') drawLevelComplete();
    else                              drawGame();
  }
}
requestAnimationFrame(loop);